// Certificate management functions
function addCertificateEntry() {
    certificate_entries.value.push({
        policy_number: '',
        certificate_number: '',
    });
}

function removeCertificateEntry(index: number) {
    if (certificate_entries.value.length <= 1) return;
    certificate_entries.value.splice(index, 1);
    syncCertificateNumbers();
}

function syncCertificateNumbers() {
    formData.certificate_numbers = certificate_entries.value
        .map(e => e.certificate_number)
        .filter(Boolean)
        .join(',');
    (formData as Record<string, unknown>).certificate_numbers_array = certificate_entries.value
        .filter(e => e.policy_number)
        .map(e => ({
            policy_number: e.policy_number,
            certificate_number: e.certificate_number || null,
        }));
}

function openCreateCertificate() {
    editing_certificate_index.value = null;
    new_certificate.policy_number = '';
    new_certificate.certificate_number = '';
    certificate_modal_open.value = true;
}

function openEditCertificate(index: number) {
    const entry = certificate_entries.value[index];
    if (!entry) return;
    editing_certificate_index.value = index;
    new_certificate.policy_number = entry.policy_number;
    new_certificate.certificate_number = entry.certificate_number;
    certificate_modal_open.value = true;
}

async function submitNewCertificate() {
    if (!new_certificate.policy_number.trim()) return;

    const editIdx = editing_certificate_index.value;
    const isEditing = editIdx !== null && editIdx >= 0;

    if (isEditing) {
        const entry = certificate_entries.value[editIdx];
        if (!entry) return;

        try {
            entry.policy_number = new_certificate.policy_number.trim();
            entry.certificate_number = new_certificate.certificate_number || '';

            // Update via API if editing existing
            if (entry.uuid) {
                await API_SERVICE.put('/certificates/' + entry.uuid, {
                    policy_number: entry.policy_number,
                    certificate_number: entry.certificate_number,
                    closing_id: props.data?.id || null,
                });
            }

            syncCertificateNumbers();
            notif.success('Certificate updated successfully');
            certificate_modal_open.value = false;
        } catch {
            notif.failed('Failed to update certificate');
        }
        return;
    }

    // Creating new certificate
    try {
        // Generate certificate_number if not provided
        if (!new_certificate.certificate_number) {
            // Call API to generate certificate_number
            const genRes = await API_SERVICE.post('/certificates/generate', {
                policy_number: new_certificate.policy_number.trim(),
                closing_id: props.data?.id || null,
                period_from: formData.period_from || null,
                period_to: formData.period_to || null,
                insurance_type_code: formData.insurance_type_code || null,
            });
            new_certificate.certificate_number = genRes?.data?.certificate_number || '';
        }

        // Create certificate record
        const res = await API_SERVICE.post('/certificates', {
            policy_number: new_certificate.policy_number.trim(),
            certificate_number: new_certificate.certificate_number,
            closing_id: props.data?.id || null,
            period_from: formData.period_from || null,
            period_to: formData.period_to || null,
            insurance_type_code: formData.insurance_type_code || null,
        });

        const created = res?.data;
        const newIdx = certificate_entries.value.length;
        certificate_entries.value.push({
            id: created?.id,
            policy_number: new_certificate.policy_number.trim(),
            certificate_number: new_certificate.certificate_number,
        });

        await nextTick();
        certificate_autocomplete_refs.value[newIdx]?.setQuery(new_certificate.policy_number.trim());
        syncCertificateNumbers();
        notif.success('Certificate created successfully');
        certificate_modal_open.value = false;
    } catch {
        notif.failed('Failed to create certificate');
    }
}

